  -- ── SEQUENCES ─────────────────────────────────────────────────────────────

  CREATE SEQUENCE IF NOT EXISTS admin_users_id_seq START WITH 1 INCREMENT BY 1;
  CREATE SEQUENCE IF NOT EXISTS comments_id_seq START WITH 1 INCREMENT BY 1;
  CREATE SEQUENCE IF NOT EXISTS events_id_seq START WITH 1 INCREMENT BY 1;
  CREATE SEQUENCE IF NOT EXISTS link_clicks_id_seq START WITH 1 INCREMENT BY 1;
  CREATE SEQUENCE IF NOT EXISTS newsletter_subscribers_id_seq START WITH 1 INCREMENT BY 1;
  CREATE SEQUENCE IF NOT EXISTS post_versions_id_seq START WITH 1 INCREMENT BY 1;
  CREATE SEQUENCE IF NOT EXISTS post_views_id_seq START WITH 1 INCREMENT BY 1;
  CREATE SEQUENCE IF NOT EXISTS posts_id_seq START WITH 1 INCREMENT BY 1;
  CREATE SEQUENCE IF NOT EXISTS promotion_bookings_id_seq START WITH 1 INCREMENT BY 1;

  -- ── TABLES ────────────────────────────────────────────────────────────────

  CREATE TABLE IF NOT EXISTS admin_users (
    id INTEGER PRIMARY KEY DEFAULT nextval('admin_users_id_seq'),
    email TEXT NOT NULL UNIQUE,
    password_hash TEXT,
    role TEXT NOT NULL DEFAULT 'editor',
    invite_token TEXT,
    invite_accepted BOOLEAN DEFAULT false,
    is_active BOOLEAN DEFAULT true,
    created_at TIMESTAMP DEFAULT now()
  );

  CREATE TABLE IF NOT EXISTS posts (
    id INTEGER PRIMARY KEY DEFAULT nextval('posts_id_seq'),
    title TEXT NOT NULL,
    slug TEXT NOT NULL UNIQUE,
    excerpt TEXT,
    content TEXT,
    cover_image_url TEXT,
    is_published BOOLEAN DEFAULT false,
    is_gated BOOLEAN DEFAULT false,
    published_at TIMESTAMP,
    created_at TIMESTAMP DEFAULT now(),
    updated_at TIMESTAMP DEFAULT now()
  );

  CREATE TABLE IF NOT EXISTS events (
    id INTEGER PRIMARY KEY DEFAULT nextval('events_id_seq'),
    title TEXT NOT NULL,
    description TEXT NOT NULL,
    date TEXT NOT NULL,
    region TEXT NOT NULL,
    image_url TEXT NOT NULL,
    ticket_link TEXT,
    created_at TIMESTAMP DEFAULT now(),
    city TEXT,
    event_time TEXT,
    venue TEXT,
    organizer TEXT,
    influencer TEXT,
    genre TEXT,
    instagram_handle TEXT
  );

  CREATE TABLE IF NOT EXISTS newsletter_subscribers (
    id INTEGER PRIMARY KEY DEFAULT nextval('newsletter_subscribers_id_seq'),
    name TEXT NOT NULL,
    email TEXT NOT NULL UNIQUE,
    region TEXT,
    created_at TIMESTAMP DEFAULT now(),
    referrer TEXT,
    has_access BOOLEAN DEFAULT true
  );

  CREATE TABLE IF NOT EXISTS promotion_bookings (
    id INTEGER PRIMARY KEY DEFAULT nextval('promotion_bookings_id_seq'),
    venue_name TEXT NOT NULL,
    contact_name TEXT,
    phone TEXT,
    email TEXT NOT NULL,
    event_date TEXT NOT NULL,
    region TEXT NOT NULL,
    event_type TEXT NOT NULL,
    budget_range TEXT,
    instagram_handle TEXT,
    ready_to_move_forward TEXT,
    created_at TIMESTAMP DEFAULT now(),
    mode TEXT,
    event_name TEXT,
    event_time TEXT,
    city TEXT,
    event_type_other TEXT,
    status TEXT DEFAULT 'New'
  );

  CREATE TABLE IF NOT EXISTS post_versions (
    id INTEGER PRIMARY KEY DEFAULT nextval('post_versions_id_seq'),
    post_id INTEGER REFERENCES posts(id),
    title TEXT NOT NULL,
    content TEXT NOT NULL,
    saved_at TIMESTAMP DEFAULT now(),
    saved_by INTEGER REFERENCES admin_users(id)
  );

  CREATE TABLE IF NOT EXISTS post_views (
    id INTEGER PRIMARY KEY DEFAULT nextval('post_views_id_seq'),
    post_id INTEGER REFERENCES posts(id),
    viewed_at TIMESTAMP DEFAULT now()
  );

  -- NOTE: link_clicks in production does NOT have source_page column
  --       (present in schema.ts but not yet pushed to production)
  CREATE TABLE IF NOT EXISTS link_clicks (
    id INTEGER PRIMARY KEY DEFAULT nextval('link_clicks_id_seq'),
    post_id INTEGER REFERENCES posts(id),
    url TEXT NOT NULL,
    clicked_at TIMESTAMP DEFAULT now()
  );

  CREATE TABLE IF NOT EXISTS comments (
    id INTEGER PRIMARY KEY DEFAULT nextval('comments_id_seq'),
    post_id INTEGER NOT NULL REFERENCES posts(id),
    parent_id INTEGER REFERENCES comments(id),
    email TEXT NOT NULL,
    body TEXT NOT NULL,
    created_at TIMESTAMP DEFAULT now()
  );

